    25→// validateStructuralCompleteness checks that all value validations in s have
    26→// a structural counterpart so that every value validation applies to a value
    27→// with a known schema:
    28→// - validations for specific properties must have that property (or additionalProperties under an option) structurally defined
    29→// - additionalProperties validations must have additionalProperties defined in the structural portion of the schema corresponding to that node
    30→// - Items validations must have also have a corresponding items structurally
    31→//
    32→// The "structural" portion of the schema refers to all nodes in the
    33→// schema traversible without following any NestedValueValidations.
    34→func validateStructuralCompleteness(s *Structural, fldPath *field.Path, opts ValidationOptions) field.ErrorList {
    35→	if s == nil {
    36→		return nil
    37→	}
    38→
    39→	return validateValueValidationCompleteness(s.ValueValidation, s, fldPath, fldPath, opts)
    40→}
