    42→func validateValueValidationCompleteness(v *ValueValidation, s *Structural, sPath, vPath *field.Path, opts ValidationOptions) field.ErrorList {
    43→	if v == nil {
    44→		return nil
    45→	}
    46→	if s == nil {
    47→		return field.ErrorList{field.Required(sPath, fmt.Sprintf("because it is defined in %s", vPath.String()))}
    48→	}
    49→
    50→	allErrs := field.ErrorList{}
    51→
    52→	allErrs = append(allErrs, validateNestedValueValidationCompleteness(v.Not, s, sPath, vPath.Child("not"), opts)...)
    53→	for i := range v.AllOf {
    54→		allErrs = append(allErrs, validateNestedValueValidationCompleteness(&v.AllOf[i], s, sPath, vPath.Child("allOf").Index(i), opts)...)
    55→	}
    56→	for i := range v.AnyOf {
    57→		allErrs = append(allErrs, validateNestedValueValidationCompleteness(&v.AnyOf[i], s, sPath, vPath.Child("anyOf").Index(i), opts)...)
    58→	}
